function sendMessage(e){const t=document.querySelector("iframe.giscus-frame");if(!t)return;t.contentWindow.postMessage({giscus:e},"https://giscus.app")}window.addEventListener("theme-change",e=>{const t=window.giscusCssDark,n=window.giscusCssLight;console.log(t);const s=document.getElementById("giscus");s&&(s.dataset.theme=e.detail.theme==="dark"?t:n),sendMessage({setConfig:{theme:e.detail.theme==="dark"?t:n}})})